VALUES
  ('disabled-6f0ba476-moex-00571', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-110-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '乙公司 X5 年在現金流量表部分資料如下：特別股轉換成普通股$280,000 ，發放股票股利$450,000，購買設備付款$850,000，開立一張抵押票據購買 土地$2,500,000，出售按攤銷後成本衡量之投資得款$500,000，營業活動之 淨現金流入$1,500,000。乙公司X5年度之淨現金流量為何？', '["淨現金流入$650,000", "淨現金流入$1,150,000", "淨現金流出$350,000", "淨現金流出$1,000,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:31+00:00", "source_pdf_sha1": "ae539d788f4f", "answer_pdf_sha1": "d82f2d892680", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "304", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00572', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-110-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '甲公司於X3年1月2日購買乙公司所發行的可轉換公司債作為投資，X6 年底甲公司帳上公司債之公允價值為$108,000。若甲公司於 X7 年 3 月 1 日將公司債全部轉換為普通股 4,000 股，乙公司當日普通股每股公允價值 為$30（每股面額為$10），則前述交易對甲公司 X7 年損益影響數為何？ （不考慮所得稅影響數）', '["$0", "利益$12,000", "損失$28,000", "損失$68,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:31+00:00", "source_pdf_sha1": "ae539d788f4f", "answer_pdf_sha1": "d82f2d892680", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "304", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00573', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-110-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '甲公司在 X1 年 4 月 1 日取得一部設備，成本$580,000，估計耐用年限 5 年，殘值$40,000，後續衡量採成本模式。該設備原係以年數合計法提列折 舊，直至X3年初，甲公司決定改採直線法提列折舊。若所得稅率為20% ，改變折舊方法對X3年本期淨利之淨影響為何？（答案四捨五入至元）', '["本期淨利增加$7,200", "本期淨利增加$31,570", "本期淨利增加$31,466", "本期淨利增加$39,462"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:31+00:00", "source_pdf_sha1": "ae539d788f4f", "answer_pdf_sha1": "d82f2d892680", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "304", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00574', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-110-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '乙銀行於Xl年1月1日發行面額$1,000,000之債券，票面附息4%，三年 到期，每年12月31日付息，按$972,768價格發行。若乙銀行將發行債券 所得款項放款給甲客戶，利率 6%，三年到期，每年 12 月 31 日付息，合 約規定借款人（甲客戶）可隨時購買乙銀行發行之前述債券提前償還該借 款。乙銀行將該放款分類為透過損益按公允價值衡量之金融資產，同時也 將所發行之債券指定為透過損益按公允價值衡量。X1 年 1 月 1 日乙銀行 所發行債券之有效利率為 5%，此時指標利率為 4%。X1 年 12 月31 日該 債券之公允價值為$928,669，有效利率為 8%，指標利率為 6%。則 X1 年 度與該指定透過損益按公允價值衡量金融負債相關之其他綜合損益為多 少？（不考慮所得稅之影響，四捨五入取至元）', '["$0", "$17,090", "$44,099", "$52,737"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:31+00:00", "source_pdf_sha1": "ae539d788f4f", "answer_pdf_sha1": "d82f2d892680", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "304", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00575', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-110-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '假設公允價值能可靠衡量，下列資產項目中有幾項在原始認列時應以成本', '["生產性動物", "生產性植物", "後續衡量採公允價值模式衡量 之投資性不動產", "後續衡量採成本模式衡量之投資性不動產  ⑤由自 己農場收成供銷售之蘋果  ⑥由他人農場購入供銷售之蘋果"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:31+00:00", "source_pdf_sha1": "ae539d788f4f", "answer_pdf_sha1": "d82f2d892680", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "304", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00576', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-110-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', 'X1年8月1日甲公司與乙公司簽訂不可取消購貨合約，甲公司須於X4年', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:31+00:00", "source_pdf_sha1": "ae539d788f4f", "answer_pdf_sha1": "d82f2d892680", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "304", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00577', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-110-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '月 1 日前以每單位$20，向乙公司進貨 10,000 單位。另外，甲公司可於 到期前任何時點取消該合約，唯須支付罰金$50,000。甲公司會計期間採曆 年制，並評估X1年底、X2年底及X3年底該商品每單位之售價分別為$18 、$14及$16，試問，甲公司X3年度因上述合約應認列多少相關損益？', '["損失$20,000", "損失$40,000", "利益$10,000", "利益$20,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:31+00:00", "source_pdf_sha1": "ae539d788f4f", "answer_pdf_sha1": "d82f2d892680", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "304", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00578', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-110-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '甲公司在X1 年1月1 日購買一棟商業大樓，規劃將之出租以收取租金。 該棟大樓之總成本為$10,000,000，估計土地與建築物之公允價值分別為 $6,000,000與$4,000,000。甲公司於X1年3月1日以營業租賃方式出租予 乙公司，每月租金$20,000。預估該棟大樓之使用年限為25年，殘值$200,000 。X1 年底，土地與建築物之公允價值分別為$6,900,000 及$3,800,000。若 甲公司採公允價值模式衡量投資性不動產，甲公司 X1 年綜合損益表應表 達之相關損益共計多少？', '["利益$40,000", "利益$48,000", "利益$748,000", "利益$900,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:31+00:00", "source_pdf_sha1": "ae539d788f4f", "answer_pdf_sha1": "d82f2d892680", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "304", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00579', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-110-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '甲公司於X3年1月1日給與30位員工每人1,500單位認股權。其條件為 員工必須自 X3 年 1 月 1 日起連續服務滿 3 年，且 X5 年底公司股價須大 於$40，始能既得。該認股權之存續期間6年、履約價格$35，給與日之股 票評估價值$35，但無法可靠估計所給與認股權之公允價值。假設X3年至 X6 年底，該方案在職人數分別為 28、26、24、22，股票評估價值分別為 $36、$37、$41、$43。X5 年底有 4 人執行該認股權（其中 2 人於隔年離 職），X6年初有5人執行該認股權。試問，甲公司X6年度應認列該方案 相關之薪資費用為何？', '["$(18,000)", "$0", "$45,000", "$60,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:31+00:00", "source_pdf_sha1": "ae539d788f4f", "answer_pdf_sha1": "d82f2d892680", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "304", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00580', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-110-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '甲公司於X1年初購入乙公司60%之普通股，成為乙公司之母公司。此外 ，甲公司於X1年9月1日購入丙公司36%之普通股，對丙公司具重大影 響力，而丙公司在X0年初就已取得丁公司25%股權，丁公司為丙公司之 關聯企業。乙公司 X1 年度出售毛利$2,000,000 之商品一批給丁公司，請 問甲公司將對乙公司股權投資採權益法處理時，應消除多少乙公司對丁公 司銷貨之未實現損益？', '["$0", "$36,000", "$108,000", "$144,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:31+00:00", "source_pdf_sha1": "ae539d788f4f", "answer_pdf_sha1": "d82f2d892680", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "304", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL)
